class Solution:
    def max_reverse_palindromic_substring(self, s: str, k: int, r: int) -> int:
        max = 0
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                substr = s[i:j]
                rev_substring = substr
                for p in range(rev_substring.length() // 2):
                    if rev_substring.length() == len(s):
                        break
                    if rev_substring.rev_substring(-p - 1) != substr[p]:
                        break
                    max += 1
                if k > 0 and r > 0:
                    max += 1
        return max;
